    gasLimits.push(withBuffer)
  } catch (e) {
    const fallback = GAS_FALLBACK[step.stepId]
    console.warn(`Gas estimation failed for ${step.stepId}, using fallback ${fallback}:`, e)
    gasLimits.push(fallback)
  }
