const { sendTransaction: sendTx, waitForTransactionReceipt } = await import('wagmi/actions')
const { wagmiConfig } = await import('@/lib/blockchain/wagmi')

// Safe bigint conversion — handles '0x0', '0', '', undefined, null
const toValue = (v: string | undefined | null): bigint => {
  if (!v || v === '0x0' || v === '0x' || v === '0') return 0n
  try { return BigInt(v) } catch { return 0n }
}

// Collect ALL transaction-kind steps in order (approve, deposit, swap, etc.)
const txSteps: Array<{
  stepId: string
  stepLabel: string
  to: `0x${string}`
  data: `0x${string}`
  value: bigint
  maxFeePerGas?: bigint
  maxPriorityFeePerGas?: bigint
  checkEndpoint?: string
}> = []

for (const step of multiQuote.steps) {
  if (step.kind !== 'transaction' || !step.items?.length) continue
  for (const item of step.items) {
    const d = item.data
    txSteps.push({
      stepId: step.id,
      stepLabel: step.id === 'approve' ? 'Approval' : step.id === 'deposit' ? 'Deposit' : step.action || step.id,
      to: d.to as `0x${string}`,
      data: d.data as `0x${string}`,
      value: toValue(d.value),
      // Pass Relay's gas price fields through exactly — they are set by Relay
      // to ensure the transaction is valid and properly priced at quote time.
      // Do NOT strip these; stripping them causes MetaMask to re-simulate with
      // different gas prices which can produce "likely to fail" warnings.
      maxFeePerGas: d.maxFeePerGas ? toValue(d.maxFeePerGas) || undefined : undefined,
      maxPriorityFeePerGas: d.maxPriorityFeePerGas ? toValue(d.maxPriorityFeePerGas) || undefined : undefined,
      checkEndpoint: item.check?.endpoint,
    })
  }
}

console.log('Total tx steps to execute:', txSteps.length, txSteps.map(s => s.stepId))

if (txSteps.length === 0) {
  toast.error('No transactions to execute in quote.')
  setIsSwapping(false)
  return
}

toast.info(`Executing ${txSteps.length} step(s)...`)

let confirmedCount = 0
const failedTxs: number[] = []

for (let i = 0; i < txSteps.length; i++) {
  const step = txSteps[i]
  console.log(`Step ${i + 1}/${txSteps.length}: ${step.stepId}`, {
    to: step.to,
    value: step.value.toString(),
  })
  try {
    const hash = await sendTx(wagmiConfig, {
      to: step.to,
      data: step.data,
      value: step.value,
      maxFeePerGas: step.maxFeePerGas,
      maxPriorityFeePerGas: step.maxPriorityFeePerGas,
    })
